// Fuse-box proposed duplicates: drop only the status==='proposed' copies.
const DROP_PROPOSED_DUP_SLUGS = new Set<string>([
  'fv_fusebox_location', 'fv_fusebox_reset_instructions',
]);

function dropQuestions(phases: FirstVisitPhase[]): FirstVisitPhase[] {
  return phases.map((p) => ({
    ...p,
    questions: p.questions.filter((q) => {
      if (DROPPED_SLUGS.has(q.slug)) return false;
      if (DROP_PROPOSED_DUP_SLUGS.has(q.slug) && q.status === 'proposed') return false;
      return true;
    }),
  }));
}

// Many XLSX-source descriptions are operational notes for PMs, not guidance
// for the field inspector ("Pre-filled from ClickUp; PM only confirms",
// "From Final Info DB; auto-fillable", etc.). They add noise on the phone.
// Anything matching these patterns is stripped to null at load time so the
// UI only ever shows descriptions that actually help fill out the question.
const OPERATIONAL_DESCRIPTION_PATTERNS: RegExp[] = [
  /\bPM\b/,
  /clickup/i,
  /final info db/i,
  /auto[- ]?fill/i,
  /auto[- ]?generated/i,
  /pre[- ]?filled/i,
  /host faq/i,
  /\bdata point\b/i,
  /deals table/i,
  /validates_host_faq/i,
  /\bfv_/,
  /\[gaps/i,
  /resumable post-visit/i,
  /geoapify/i,
  /hub auto/i,
  /from hub\b/i,
  /^dropdown of/i,
];

function isOperationalDescription(d: string | null | undefined): boolean {
  if (!d) return false;
  return OPERATIONAL_DESCRIPTION_PATTERNS.some((p) => p.test(d));
}

function stripOperationalDescriptions(phases: FirstVisitPhase[]): FirstVisitPhase[] {
  return phases.map((p) => ({
    ...p,
    questions: p.questions.map((q) =>
      isOperationalDescription(q.description) ? { ...q, description: null } : q,
    ),
  }));
}

// Some XLSX rows describe data that lives on the `deals` table itself (stampings
// like `deals.name`), not in the `data_points` model the survey reads from. They
// render as empty fields and duplicate info already shown elsewhere in the UI
// (e.g. the deal name is in the VisitNavigator header). Hide them entirely.
// Slugs listed here are dropped from PHASES; phases that empty out are removed.
const HIDDEN_DEAL_STAMPING_SLUGS = new Set<string>([
  'fv_visit_deal_name',
]);

function hideDealStampingQuestions(phases: FirstVisitPhase[]): FirstVisitPhase[] {
  return phases
    .map((p) => ({
      ...p,
      questions: p.questions.filter((q) => !HIDDEN_DEAL_STAMPING_SLUGS.has(q.slug)),
    }))
    .filter((p) => p.questions.length > 0);
}

// "verify" was a spec marker meaning "this is a data point the inspector should
// confirm against pre-filled hub data". It leaked into user-facing labels,
// phase labels, and descriptions. When nothing is pre-filled there is nothing
// to "verify", so the word is just confusing on the phone. Strip it from
// display strings only — slugs (DB keys like `fv_building_amenities_verify`)
// are untouched.
function cleanLabel(label: string): string {
  if (!label) return label;
  let out = label;
  // " & verify" → "" (e.g. "Unit identity & verify" → "Unit identity")
  out = out.replace(/\s*&\s*verify\b/gi, '');
  // trailing " verify" → "" (e.g. "Building amenities verify" → "Building amenities")
  out = out.replace(/\s+verify\s*$/gi, '');
  // collapse double spaces + trim
  out = out.replace(/\s{2,}/g, ' ').trim();
  return out;
}

function cleanDescription(desc: string | null): string | null {
  if (!desc) return desc;
  // standalone "verify" → "confirm" (case-insensitive, lowercase replacement)
  let out = desc.replace(/\bverify\b/gi, 'confirm');
  out = out.replace(/\s{2,}/g, ' ').trim();
  return out.length === 0 ? null : out;
}

function stripVerifyWord(phases: FirstVisitPhase[]): FirstVisitPhase[] {
  return phases.map((p) => ({
    ...p,
    label: cleanLabel(p.label),
    questions: p.questions.map((q) => ({
      ...q,
      label: cleanLabel(q.label),
      description: cleanDescription(q.description),
      phase_label: cleanLabel(q.phase_label),
    })),
  }));
}

// Defensive dedup: the XLSX-driven generator can emit the same slug twice within
// a phase (content bug). Two rows sharing a slug would collide on the Dexie
// compound key [target_id+question_key+area_key] and produce duplicate React
// keys in the survey list. Resolution: keep the first occurrence per
// (phase_id, slug), promoting it to required:true if any duplicate is required.
// In dev we log a warning so the content issue stays visible. Production stays
// silent — bad data should never crash the app.
function dedupePhases(phases: FirstVisitPhase[]): FirstVisitPhase[] {
  return phases.map((p) => {
    const byKey = new Map<string, FirstVisitQuestion>();
    const dropped: string[] = [];
    for (const q of p.questions) {
      const key = q.slug;
      const existing = byKey.get(key);
      if (!existing) {
        byKey.set(key, q);
        continue;
      }
      // Already saw this slug in this phase. Promote required if either copy
      // is required, then drop the duplicate.
      if (q.required && !existing.required) {
        byKey.set(key, { ...existing, required: true });
      } else if (existing.required || q.required) {
        byKey.set(key, { ...existing, required: true });
      }
      dropped.push(key);
    }
    if (dropped.length > 0 && typeof process !== 'undefined' && process.env.NODE_ENV !== 'production') {
      // eslint-disable-next-line no-console
      console.warn(
        `[first-visit-questions] phase ${p.id} (${p.label}) has duplicate slug(s): ${dropped.join(', ')}. ` +
          `Kept first occurrence per slug (required-promoted). Fix the source XLSX or generator.`,
      );
    }
    return { ...p, questions: Array.from(byKey.values()) };
  });
}

// --- Phase B: unified Findings repeater (review 2026-06-02 §5) ---
// One repeating "findings" block (the post-visit shopping-list + repairs model)
// injected at unit_category scope (phase 9d, Unit walkthrough) and at location
// scope (phase 5, Building infrastructure & utilities). Replaces the dropped
// 9d cost fields and 9e appliance-condition fields (see DROPPED_SLUGS).
const UNIT_WALKTHROUGH_PHASE_ID = '9d';
const BUILDING_INFRA_PHASE_ID = '5';

const FINDING_CATEGORY_OPTIONS = ['Furniture','Appliance','Equipment','Bathroom','Structural/Building','Consumable','Other'];
const FINDING_LOCATION_OPTIONS = ['Kitchen','Bathroom','Bedroom','Living room','Hallway','Balcony','Building/common','Other'];
// FINDING_RESOLUTION_OPTIONS lives in findingsResolution.ts (shared with the
// CSV export's listTypeFor) so the picker options and the list-type mapping
// can never drift.
const FINDING_URGENCY_OPTIONS = ['Blocks go-live','Nice-to-have'];

function makeFindingQuestions(scope: HubScope, phaseId: string, phaseLabel: string): FirstVisitQuestion[] {
  const base = { scope, mode: 'observe' as Mode, status: 'proposed' as Status, verdict: null,
    notes: null, repeater: true, group_id: 'finding', phase_id: phaseId, phase_label: phaseLabel };
  const q = (slug: string, label: string, type: FieldType, required: boolean,
    options: string[] = []): FirstVisitQuestion => ({ ...base, slug, label, description: null, type, required, options, pms_target: null });
  return [
    q('finding_item_name','Item / issue (clear name)','text',true),
    q('finding_category','Category','select',true,FINDING_CATEGORY_OPTIONS),
    q('finding_location','Location in unit','select',false,FINDING_LOCATION_OPTIONS),
    q('finding_resolution','Resolution','select',true,FINDING_RESOLUTION_OPTIONS),
    q('finding_quantity','Quantity','number',false),
    q('finding_cost_estimate_eur','Cost estimate (€)','number',true),
    q('finding_urgency','Urgency','select',false,FINDING_URGENCY_OPTIONS),
    q('finding_notes','Notes','text',false),
    q('finding_media','Photo / video','file',true),
  ];
}

function injectFindings(phases: FirstVisitPhase[]): FirstVisitPhase[] {
  return phases.map((p) => {
    if (p.id === UNIT_WALKTHROUGH_PHASE_ID) return { ...p, questions: [...p.questions, ...makeFindingQuestions('unit_category', p.id, p.label)] };
    if (p.id === BUILDING_INFRA_PHASE_ID) return { ...p, questions: [...p.questions, ...makeFindingQuestions('location', p.id, p.label)] };
    return p;
  });
}

// --- Phase E: Bucket-2 config fixes (review 2026-06-02) ---
// Two generic helpers drive all eight changes so we don't write a bespoke
// transform per fix:
//   overrideQuestions   — shallow-merge a Partial<FirstVisitQuestion> patch
//                         into every question whose slug matches.
//   injectBucket2Questions — append brand-new questions to a specific phase
//                         (same pattern as injectFindings).

// Shallow-merge `patchMap[slug]` into each matching question across all phases.
// Slugs in the map that match no question are silently no-ops (reported in the
// Phase E summary, not enforced here — keeps the helper generic).
export function overrideQuestions(
  phases: FirstVisitPhase[],
  patchMap: Record<string, Partial<FirstVisitQuestion>>,
): FirstVisitPhase[] {
  const matched = new Set<string>();
  const next = phases.map((p) => ({
    ...p,
    questions: p.questions.map((q) => {
      if (!patchMap[q.slug]) return q;
      matched.add(q.slug);
      return { ...q, ...patchMap[q.slug] } as FirstVisitQuestion;
    }),
  }));
  // A patch key that matches no question is a silent landmine (typo, or the
  // upstream XLSX renamed/removed a slug). Surface it in dev rather than
  // letting the override vanish without a trace.
  if (process.env.NODE_ENV !== 'production') {
    const unmatched = Object.keys(patchMap).filter((slug) => !matched.has(slug));
    if (unmatched.length > 0) {
      console.warn(`overrideQuestions: no question matched these slugs: ${unmatched.join(', ')}`);
    }
  }
  return next;
}

// Build a single new question with sane Phase-E defaults (proposed status,
// non-repeater, no pms_target unless overridden). Mirrors makeFindingQuestions'
// `q` builder so injected rows are shaped like the generated ones.
function makeBucket2Question(
  phase: FirstVisitPhase,
  scope: HubScope,
  partial: Partial<FirstVisitQuestion> & Pick<FirstVisitQuestion, 'slug' | 'label' | 'type'>,
): FirstVisitQuestion {
  return {
    description: null,
    scope,
    mode: 'observe',
    options: [],
    required: false,
    repeater: false,
    pms_target: null,
    status: 'proposed',
    verdict: null,
    notes: null,
    phase_id: phase.id,
    phase_label: phase.label,
    ...partial,
  };
}

function injectBucket2Questions(phases: FirstVisitPhase[]): FirstVisitPhase[] {
  return phases.map((p) => {
    // E2 + E3 — parking phase (id '3'), location scope.
    if (p.id === '3') {
      const additions: FirstVisitQuestion[] = [
        makeBucket2Question(p, 'location', {
          slug: 'fv_parking_spot_number',
          label: 'Exact parking spot number',
          type: 'text',
          required: false,
        }),
        makeBucket2Question(p, 'location', {
          slug: 'fv_photo_parking_spot',
          label: 'Photo of the parking spot',
          type: 'file',
          required: true,
          anchor_to: 'fv_parking_dedicated_spots',
        }),
      ];
      return { ...p, questions: [...p.questions, ...additions] };
    }
    // E6 — fuse box media, infrastructure phase (id '5'), location scope.
    if (p.id === '5') {
      const additions: FirstVisitQuestion[] = [
        makeBucket2Question(p, 'location', {
          slug: 'fv_video_fusebox',
          label: 'Fuse box video (reset/operation)',
          type: 'file',
          required: false,
          anchor_to: 'fv_fusebox_location',
        }),
        makeBucket2Question(p, 'location', {
          slug: 'fv_photo_fusebox_location',
          label: 'Photo of fuse box location',
          type: 'file',
          required: true,
          anchor_to: 'fv_fusebox_location',
        }),
      ];
      return { ...p, questions: [...p.questions, ...additions] };
    }
    return p;
  });
}

